import React, { useEffect, useState } from 'react';
import { Category } from '../types';
import api from '../utils/api';

export default function Categories() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/borrows/categories').then(r => { setCategories(r.data.data); setLoading(false); });
  }, []);

  return (
    <div className="page-enter" style={{ padding:32 }}>
      <div style={{ marginBottom:24 }}>
        <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:28, fontWeight:700 }}>Categories</h1>
        <p style={{ color:'#9ca3af', fontSize:13, marginTop:4 }}>Browse books by genre</p>
      </div>
      {loading ? <div style={{ textAlign:'center', padding:80, color:'#9ca3af' }}>Loading...</div> : (
        <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:16 }}>
          {categories.map(cat => (
            <div key={cat.id} style={{ background:'#fff', border:'1px solid #e8e0d0', borderRadius:16, padding:22, transition:'all .25s', cursor:'default' }}>
              <div style={{ width:48, height:48, borderRadius:12, background:cat.color+'20', display:'flex', alignItems:'center', justifyContent:'center', fontSize:24, marginBottom:14 }}>📂</div>
              <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:17, fontWeight:700, marginBottom:6 }}>{cat.name}</h3>
              <p style={{ fontSize:12, color:'#9ca3af', marginBottom:14, lineHeight:1.5 }}>{cat.description}</p>
              <div style={{ borderTop:'1px solid #e8e0d0', paddingTop:12, display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                <div>
                  <span style={{ fontFamily:"'Playfair Display',serif", fontSize:22, fontWeight:700, color:cat.color }}>{cat.book_count}</span>
                  <span style={{ fontSize:12, color:'#9ca3af', marginLeft:4 }}>books</span>
                </div>
                <span style={{ fontSize:11, fontWeight:600, padding:'3px 10px', borderRadius:99, background:'#d1fae5', color:'#059669' }}>Active</span>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
